import { promises as fs } from "node:fs";
import path from "node:path";
import { createHash } from "node:crypto";

/**
 * Founder media UPLOAD ingest for the Content Library.
 *
 * Until now content assets could only appear two ways: imported from an approved content packet
 * (`importFromContentPacket`) or generated by Media Studio. Neither of those covers the most common
 * real case — the founder shot a reel on their phone, or has a designed image, and wants it in the
 * Library so the scheduler can post it. This module is that missing first step, and NOTHING else:
 * bytes in → a validated, content-addressed file under STORAGE_ROOT/media → a `media/<hash>.<ext>`
 * ref. Everything downstream (`addContentAsset`, `schedulePost`, `dispatchDuePosts`, the Zernio
 * adapter, `serveLibraryMedia`) already exists and is reused unchanged.
 *
 * STORAGE CONVENTION — deliberately identical to `src/lib/media/openrouter-provider.ts`:
 *   file  → `<STORAGE_ROOT>/media/<sha256(bytes).slice(0,32)><ext>`
 *   ref   → `media/<hash><ext>`  (relative; `serveLibraryMedia` resolves it against STORAGE_ROOT and
 *            refuses anything that escapes that directory)
 * There is exactly ONE media layout in this system. A second one would silently break serving,
 * the standalone build's file tracing, and the VPS volume mapping.
 *
 * WHY CONTENT-ADDRESSING: the filename is derived from the bytes, so (a) re-uploading the same reel
 * is a no-op that reuses the existing file instead of filling the disk with duplicates, and (b) the
 * client-supplied filename NEVER reaches the filesystem. A caller cannot influence the path at all —
 * not via `../`, not via a null byte, not via a 4 GB name. That is the primary security property of
 * this module, and it is why the name is not "sanitised" from user input but *replaced* by a hash.
 *
 * WHY AN ALLOWLIST (never a denylist): this accepts founder-supplied bytes and writes them to a
 * directory the app serves back over HTTP. A denylist ("block .exe/.svg/.html") is a guessing game
 * that loses to the next content type someone invents; an allowlist can only ever be too strict,
 * which is a bug report rather than a stored-XSS or a hosted malware dropper. Note what is NOT here:
 * `image/svg+xml` (SVG is an active document — script executes when served same-origin) and
 * `text/html`. The extension is derived from the VALIDATED mime type, never from the filename, so a
 * file called `payload.exe` uploaded as `image/png` lands as `<hash>.png` and is served as an image.
 */

// ---------------------------------------------------------------- typed errors

/** The mime type is not on the allowlist. The route maps this to HTTP 415. */
export class UnsupportedMediaTypeError extends Error {
  readonly name = "UnsupportedMediaTypeError";
  constructor(readonly mimeType: string) {
    super(
      `unsupported media type '${mimeType}' — the Content Library accepts ${Object.keys(ALLOWED_MEDIA_TYPES).join(", ")} only`,
    );
  }
}

/** The decoded payload exceeds the per-kind size cap. The route maps this to HTTP 413. */
export class MediaTooLargeError extends Error {
  readonly name = "MediaTooLargeError";
  constructor(
    readonly bytes: number,
    readonly limitBytes: number,
    readonly kind: UploadedMediaKind,
  ) {
    super(`${kind} is too large: ${bytes} bytes exceeds the ${limitBytes} byte limit`);
  }
}

/**
 * The base64 payload is absent/malformed. Separated from the two above so the route can answer 422
 * ("your request was wrong") rather than a generic 500 ("we broke") — a malformed upload is never a
 * server fault, and reporting it as one hides real failures.
 */
export class InvalidMediaPayloadError extends Error {
  readonly name = "InvalidMediaPayloadError";
  constructor(reason: string) {
    super(`invalid upload payload: ${reason}`);
  }
}

// ---------------------------------------------------------------- allowlist + limits

export type UploadedMediaKind = "image" | "video";

interface AllowedType {
  ext: string;
  kind: UploadedMediaKind;
}

/**
 * THE allowlist. `ext` is the extension we write — canonical per type, so `image/jpeg` is always
 * `.jpg` (never `.jpeg`/`.JPG`) and identical bytes always produce an identical ref regardless of
 * what the uploader's OS called the file.
 *
 * Every extension here is already known to `CONTENT_TYPES` in `library/media-serve.ts`, so an
 * uploaded file is served back with its correct Content-Type rather than a download-forcing
 * `application/octet-stream`. Adding a type here means adding it there too.
 */
export const ALLOWED_MEDIA_TYPES: Readonly<Record<string, AllowedType>> = {
  "image/png": { ext: ".png", kind: "image" },
  "image/jpeg": { ext: ".jpg", kind: "image" },
  "image/webp": { ext: ".webp", kind: "image" },
  "image/gif": { ext: ".gif", kind: "image" },
  "video/mp4": { ext: ".mp4", kind: "video" },
  "video/quicktime": { ext: ".mov", kind: "video" }, // what an iPhone hands you
  "video/webm": { ext: ".webm", kind: "video" },
};

/**
 * Size caps. A phone-shot vertical reel is typically 10–80 MB, so 200 MB leaves real headroom while
 * still bounding a single request; images are capped far lower because a legitimate social image is
 * never 25 MB and a huge one is either a mistake or an attempt to fill the volume.
 */
export const DEFAULT_MAX_VIDEO_BYTES = 200 * 1024 * 1024;
export const DEFAULT_MAX_IMAGE_BYTES = 25 * 1024 * 1024;

export interface StoreUploadedMediaInput {
  /** The uploader's filename. Used ONLY for a human-readable title upstream — never for the path. */
  filename: string;
  mimeType: string;
  /** Raw base64, or a `data:<type>;base64,<payload>` URL (what FileReader.readAsDataURL produces). */
  dataBase64: string;
}

export interface StoreUploadedMediaOptions {
  /** Override STORAGE_ROOT — used by tests to write into a temp dir instead of the real volume. */
  storageRoot?: string;
  /** Override the size caps (tests use tiny values so they need not allocate 200 MB of buffer). */
  maxBytes?: { image?: number; video?: number };
}

export interface StoredUploadedMedia {
  /** `media/<hash><ext>` — exactly what goes into a ContentAsset's `mediaRefs[].path`. */
  mediaRef: string;
  bytes: number;
  kind: UploadedMediaKind;
  /** The normalised, allowlisted mime type (parameters stripped, lower-cased). */
  contentType: string;
}

/**
 * Extension → mime, derived FROM the allowlist so the two can never disagree, plus the spellings a
 * real folder contains that are not our canonical extension (`.jpeg`). Used by the folder importer,
 * which knows a file path rather than a browser-supplied mime type.
 */
const MIME_BY_EXTENSION: Readonly<Record<string, string>> = {
  ...Object.fromEntries(Object.entries(ALLOWED_MEDIA_TYPES).map(([mime, { ext }]) => [ext, mime])),
  ".jpeg": "image/jpeg",
};

/** `foo.PNG` / `.png` / `png` → `image/png`. Null when the extension is not on the allowlist. */
export function mimeTypeForExtension(extOrPath: string): string | null {
  const raw = extOrPath.includes(".") ? extOrPath.slice(extOrPath.lastIndexOf(".")) : `.${extOrPath}`;
  return MIME_BY_EXTENSION[raw.toLowerCase()] ?? null;
}

// ---------------------------------------------------------------- helpers

function resolveStorageRoot(opts?: StoreUploadedMediaOptions): string {
  // `||` rather than `??` at each step: an empty/whitespace STORAGE_ROOT is a misconfiguration, not
  // an instruction to write to the filesystem root.
  const injected = (opts?.storageRoot ?? "").trim();
  const fromEnv = (process.env.STORAGE_ROOT ?? "").trim();
  return injected || fromEnv || path.join(process.cwd(), "storage");
}

/**
 * `image/JPEG; charset=binary` → `image/jpeg`. Browsers and multipart encoders attach parameters and
 * inconsistent casing; the allowlist is keyed on the bare, lower-cased type, so normalise before
 * looking it up rather than widening the allowlist with every spelling.
 */
export function normalizeMimeType(raw: string): string {
  return raw.split(";")[0]!.trim().toLowerCase();
}

/** Resolve a mime type against the allowlist, or throw. Exported so callers can pre-validate. */
export function resolveAllowedMediaType(rawMimeType: string): AllowedType & { contentType: string } {
  const contentType = normalizeMimeType(rawMimeType);
  const allowed = ALLOWED_MEDIA_TYPES[contentType];
  if (!allowed) throw new UnsupportedMediaTypeError(contentType || rawMimeType);
  return { ...allowed, contentType };
}

const BASE64_CHARS = /^[A-Za-z0-9+/]+={0,2}$/;

/**
 * Strip an optional data-URL prefix and all whitespace, then verify the remainder really is base64.
 *
 * `Buffer.from(x, "base64")` is famously permissive — it silently DISCARDS invalid characters and
 * returns a shorter buffer, so garbage in produces a plausible-looking file rather than an error.
 * Validating first means a corrupted upload fails loudly at the door instead of becoming a 3-byte
 * "video" that only reveals itself when a publish attempt fails days later.
 */
function decodeBase64Strict(dataBase64: string, limitBytes: number, kind: UploadedMediaKind): Buffer {
  const withoutPrefix = dataBase64.startsWith("data:")
    ? dataBase64.slice(dataBase64.indexOf(",") + 1)
    : dataBase64;
  const cleaned = withoutPrefix.replace(/\s+/g, "");
  if (cleaned.length === 0) throw new InvalidMediaPayloadError("dataBase64 is empty");
  if (!BASE64_CHARS.test(cleaned)) throw new InvalidMediaPayloadError("dataBase64 is not valid base64");

  // Reject on the ENCODED length before allocating. 4 base64 chars → 3 bytes, so this bounds the
  // decode: an attacker cannot make us materialise a multi-gigabyte Buffer just to then reject it.
  const estimatedBytes = Math.floor((cleaned.length * 3) / 4);
  if (estimatedBytes > limitBytes) throw new MediaTooLargeError(estimatedBytes, limitBytes, kind);

  const bytes = Buffer.from(cleaned, "base64");
  if (bytes.byteLength === 0) throw new InvalidMediaPayloadError("dataBase64 decoded to zero bytes");
  // Authoritative check on the real decoded size (the estimate above is only an upper bound).
  if (bytes.byteLength > limitBytes) throw new MediaTooLargeError(bytes.byteLength, limitBytes, kind);
  return bytes;
}

// ---------------------------------------------------------------- ingest

function limitFor(kind: UploadedMediaKind, opts: StoreUploadedMediaOptions): number {
  return kind === "video"
    ? (opts.maxBytes?.video ?? DEFAULT_MAX_VIDEO_BYTES)
    : (opts.maxBytes?.image ?? DEFAULT_MAX_IMAGE_BYTES);
}

/**
 * The ONE place bytes become a file. Both entry points (base64 upload and on-disk folder import)
 * funnel through here, so there is a single hashing rule, a single storage layout and a single
 * containment assertion — no second implementation to drift.
 */
async function persistBytes(bytes: Buffer, ext: string, opts: StoreUploadedMediaOptions): Promise<string> {
  // Content-addressed name: sha256 of the bytes, first 32 hex chars, plus the mime-derived
  // extension. Same slice length as the media providers so every file under media/ looks the same.
  const hash = createHash("sha256").update(bytes).digest("hex").slice(0, 32);
  const name = `${hash}${ext}`;

  const mediaDir = path.resolve(resolveStorageRoot(opts), "media");
  const full = path.resolve(mediaDir, name);
  // `name` is [0-9a-f]{32} + a fixed extension, so this can never fail — which is exactly why it is
  // asserted. If a future edit ever lets caller input near the filename, this stops it becoming a
  // write outside the media directory rather than discovering it in an incident review.
  if (full !== mediaDir && !full.startsWith(mediaDir + path.sep)) {
    throw new Error("refusing to write outside the media directory");
  }

  await fs.mkdir(mediaDir, { recursive: true });
  // Identical bytes → identical path. Skip the rewrite (a re-uploaded 180 MB reel is a stat, not a
  // second 180 MB write). Size is checked too so a previously truncated/partial write self-heals.
  const existing = await fs.stat(full).catch(() => null);
  if (!existing || existing.size !== bytes.byteLength) {
    await fs.writeFile(full, bytes);
  }
  return `media/${name}`;
}

/**
 * Validate + store one founder-supplied file and return the ref the Library speaks.
 *
 * Pure enough to unit test with no DB and no network: inject `storageRoot` and it touches only that
 * directory. The caller (the API route) is responsible for auth and for creating the asset row.
 */
export async function storeUploadedMedia(
  input: StoreUploadedMediaInput,
  opts: StoreUploadedMediaOptions = {},
): Promise<StoredUploadedMedia> {
  const { ext, kind, contentType } = resolveAllowedMediaType(input.mimeType);
  const bytes = decodeBase64Strict(input.dataBase64, limitFor(kind, opts), kind);
  const mediaRef = await persistBytes(bytes, ext, opts);
  return { mediaRef, bytes: bytes.byteLength, kind, contentType };
}

/**
 * The same ingest, for a file that is ALREADY on the server's disk (the bulk folder importer).
 *
 * Deliberately not "just base64 the file and call storeUploadedMedia": that would inflate a 180 MB
 * reel to a 240 MB string for no reason. It shares every rule that matters — the same allowlist, the
 * same caps, the same sha256 content-addressing, the same single write path — because all of that
 * lives in `resolveAllowedMediaType` and `persistBytes` rather than in either entry point.
 *
 * The size cap is enforced from `stat` BEFORE the read, so an oversize file is refused without ever
 * being pulled into memory.
 */
export async function storeUploadedFile(
  absPath: string,
  opts: StoreUploadedMediaOptions & { mimeType?: string } = {},
): Promise<StoredUploadedMedia> {
  // No mime type is supplied by a filesystem, so it comes from the extension — which for a file we
  // are reading (rather than one an untrusted client named) is the only signal there is.
  const mimeType = opts.mimeType ?? mimeTypeForExtension(absPath) ?? "";
  const { ext, kind, contentType } = resolveAllowedMediaType(mimeType);

  const limitBytes = limitFor(kind, opts);
  const stat = await fs.stat(absPath);
  if (!stat.isFile()) throw new InvalidMediaPayloadError(`${absPath} is not a file`);
  if (stat.size === 0) throw new InvalidMediaPayloadError(`${absPath} is empty`);
  if (stat.size > limitBytes) throw new MediaTooLargeError(stat.size, limitBytes, kind);

  const bytes = await fs.readFile(absPath);
  // Re-check post-read: the file could have grown between the stat and the read.
  if (bytes.byteLength > limitBytes) throw new MediaTooLargeError(bytes.byteLength, limitBytes, kind);

  const mediaRef = await persistBytes(bytes, ext, opts);
  return { mediaRef, bytes: bytes.byteLength, kind, contentType };
}

/**
 * A display title for an uploaded file, derived from the client filename.
 *
 * The filename is UNTRUSTED and is used for this and nothing else. We take the last path segment
 * (splitting on both separators — a Windows client sends backslashes), drop the extension, collapse
 * separators to spaces and clamp the length. It never reaches the filesystem, so the only risk being
 * managed here is a silly-looking title.
 */
export function titleFromFilename(filename: string, fallback = "Uploaded media"): string {
  const base = filename.split(/[\\/]/).pop() ?? "";
  const withoutExt = base.replace(/\.[A-Za-z0-9]{1,8}$/, "");
  const cleaned = withoutExt.replace(/[_-]+/g, " ").replace(/\s+/g, " ").trim();
  return (cleaned || fallback).slice(0, 140);
}
